def count_tokens_rough(messages: list[dict]) -> int:
    """
    Fast token estimate: ~0.25 tokens per character of serialised content.
    Good enough for windowing decisions; use response.usage for exact counts.
    """
    total = 0
    for m in messages:
        content = m.get("content", "")
        if isinstance(content, str):
            total += len(content)
        elif isinstance(content, list):
            for block in content:
                if isinstance(block, dict):
                    total += len(block.get("text", ""))
                    total += len(str(block.get("input", "")))
                    total += len(block.get("content", ""))
    return int(total * 0.25)


def record_actual_usage(response, context_log: list) -> None:
    """
    Append the actual token counts from the API response.
    response.usage contains input_tokens and output_tokens.
    """
    context_log.append({
        "step": len(context_log),
        "input_tokens": response.usage.input_tokens,
        "output_tokens": response.usage.output_tokens,
        "total": response.usage.input_tokens + response.usage.output_tokens,
    })


