import pytest


class TestCountTokensRough:
    def test_empty(self):
        assert count_tokens_rough([]) == 0

    def test_string_content(self):
        msgs = [{"role": "user", "content": "hello world"}]  # 11 chars
        assert count_tokens_rough(msgs) == int(11 * 0.25)

    def test_list_content(self):
        msgs = [{"role": "assistant", "content": [
            {"type": "text", "text": "A" * 400}
        ]}]
        assert count_tokens_rough(msgs) == 100  # 400 * 0.25


class TestTrimToWindow:
    def _make_messages(self, n_pairs: int) -> list[dict]:
        """Create task + n_pairs of (assistant, user) turns."""
        msgs = [{"role": "user", "content": "task"}]
        for i in range(n_pairs):
            msgs.append({"role": "assistant", "content": [
                {"type": "text", "text": "A" * 800}
            ]})
            msgs.append({"role": "user", "content": [
                {"type": "tool_result", "content": "B" * 800}
            ]})
        return msgs

    def test_preserves_task(self):
