        trimmed = trim_to_window(msgs, max_tokens=200)
        assert trimmed[0]["content"] == "task"

    def test_reduces_length(self):
        msgs = self._make_messages(5)
        trimmed = trim_to_window(msgs, max_tokens=200)
        assert len(trimmed) < len(msgs)

    def test_alternating_invariant(self):
        msgs = self._make_messages(4)
        trimmed = trim_to_window(msgs, max_tokens=200)
        roles = [m["role"] for m in trimmed]
        for i in range(len(roles) - 1):
