import json
import pathlib


def save_checkpoint(messages: list[dict], path: str) -> None:
    """
    Persist the working context to disk between loop steps.
    Allows resuming a long-running agent after a crash or restart.
    """
    pathlib.Path(path).write_text(json.dumps(messages, indent=2))


def load_checkpoint(path: str) -> list[dict] | None:
    """Return messages if a checkpoint exists, else None."""
    p = pathlib.Path(path)
    if p.exists():
        return json.loads(p.read_text())
    return None


def run_with_resume(task: str, checkpoint_path: str, tools: list[dict]) -> str:
    """
    Agent loop that resumes from a saved checkpoint if one exists.
    Saves a checkpoint after every tool-result exchange.
    """
    import anthropic
    client = anthropic.Anthropic()

    messages = load_checkpoint(checkpoint_path)
    if messages is None:
        messages = [{"role": "user", "content": task}]

    while True:
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )
        messages = messages + [{"role": "assistant", "content": response.content}]

        if response.stop_reason == "end_turn":
            # Done — clean up checkpoint
            pathlib.Path(checkpoint_path).unlink(missing_ok=True)
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": dispatch_tool(block.name, block.input),
                })
        if tool_results:
            messages = messages + [{"role": "user", "content": tool_results}]
            save_checkpoint(messages, checkpoint_path)


def dispatch_tool(name: str, input: dict) -> str:
    return f"result of {name}"

import json


def format_context_for_debug(messages: list[dict], max_content_chars: int = 200) -> str:
    """
    Compact debug representation of the messages list.
    Useful for logging context state at each loop step.
    """
    lines = []
    for i, msg in enumerate(messages):
        role = msg["role"]
        content = msg.get("content", "")
        if isinstance(content, str):
            preview = content[:max_content_chars]
            lines.append(f"  [{i}] {role}: {preview!r}")
        elif isinstance(content, list):
            for j, block in enumerate(content):
                btype = block.get("type", "?")
                if btype == "text":
                    preview = block.get("text", "")[:max_content_chars]
                    lines.append(f"  [{i}.{j}] {role}/text: {preview!r}")
                elif btype == "tool_use":
                    inp = json.dumps(block.get("input", {}))[:max_content_chars]
                    lines.append(f"  [{i}.{j}] {role}/tool_use({block['name']}): {inp}")
                elif btype == "tool_result":
                    val = str(block.get("content", ""))[:max_content_chars]
                    lines.append(f"  [{i}.{j}] {role}/tool_result({block['tool_use_id'][:8]}…): {val!r}")
                else:
                    lines.append(f"  [{i}.{j}] {role}/{btype}")
    return "\n".join(lines)


